/**
 * Map over elements matching a selector.
 * @param {ParentNode} root
 * @param {string} selector
 * @param {(element: Element, index: number) => unknown} callback
 * @returns {unknown[]}
 */
export function mapElements(root, selector, callback) {
  const nodes = root.querySelectorAll(selector);
  const results = [];
  nodes.forEach((element, index) => {
    results.push(callback(element, index));
  });
  return results;
}
